// Validacao KPI1: saldo total sob gestao por agencia
const GABARITO_SALDO    = 26509620.12;
const GABARITO_AGENCIAS = 10;
const TOLERANCIA        = 0.10;

const rows = $input.all();
const totalSaldo  = rows.reduce((s, r) => s + parseFloat(r.json.saldo_total || 0), 0);
const qtdAgencias = rows.length;
const diferenca   = Math.abs(totalSaldo - GABARITO_SALDO);
const aprovado    = diferenca <= TOLERANCIA && qtdAgencias === GABARITO_AGENCIAS;

console.log(`KPI1 saldo=${totalSaldo.toFixed(2)} | agencias=${qtdAgencias} | dif=${diferenca.toFixed(4)} | ${aprovado ? 'APROVADO' : 'FALHOU'}`);

return [{
  json: {
    kpi:             'KPI1',
    status:          aprovado ? 'APROVADO' : 'FALHOU',
    aprovado,
    saldo_calculado: totalSaldo.toFixed(2),
    saldo_gabarito:  GABARITO_SALDO.toFixed(2),
    diferenca:       diferenca.toFixed(4),
    qtd_agencias:    qtdAgencias,
    timestamp:       new Date().toISOString()
  }
}];
